import{_ as a,o as s,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Compromised Passwords","description":"","frontmatter":{},"headers":[],"relativePath":"guides/passwords.md","filePath":"guides/passwords.md"}'),o={name:"guides/passwords.md"};function n(r,e,l,d,h,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="compromised-passwords" tabindex="-1">Compromised Passwords <a class="header-anchor" href="#compromised-passwords" aria-label="Permalink to &quot;Compromised Passwords&quot;">​</a></h1><p>Automated credential-stuffing attacks use known leaked password lists — the same lists from major data breaches like RockYou. When an attacker tries a password your honeypot recognises, the alert escalates immediately to <strong>Attacking</strong>, the highest severity level.</p><p>This guide explains how the detection works and how to configure it.</p><h2 id="why-truncated-sha256-instead-of-bcrypt" tabindex="-1">Why truncated SHA256 instead of bcrypt <a class="header-anchor" href="#why-truncated-sha256-instead-of-bcrypt" aria-label="Permalink to &quot;Why truncated SHA256 instead of bcrypt&quot;">​</a></h2><p>The naive approach would be to store bcrypt hashes and run <code>password_verify()</code> for each submitted password. The problem: bcrypt is intentionally slow. Checking every password in your list on every login attempt would add hundreds of milliseconds to every trap response — creating a timing oracle that reveals how many hashes you have.</p><p>NotTodayHoney uses a different approach:</p><ol><li>The submitted password is combined with a <strong>salt</strong> and hashed with SHA256</li><li>Only the <strong>first 8 hex characters</strong> of the hash are kept</li><li>That 8-character string is compared against your list</li></ol><p>The comparison is fast and constant-time. The salt makes rainbow tables useless. Truncation reduces the risk of the list itself being useful to an attacker if <code>.env</code> is ever exposed.</p><h2 id="setup-generate-a-salt" tabindex="-1">Setup: generate a salt <a class="header-anchor" href="#setup-generate-a-salt" aria-label="Permalink to &quot;Setup: generate a salt&quot;">​</a></h2><p>Run this once per application:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> honey:generate-salt</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NOT_TODAY_HONEY_PASSWORD_SALT=a3f8c2e1d9b74056</span></span></code></pre></div><p>Add the output line to your <code>.env</code>. Do not commit it.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you change the salt, all existing custom hashes become invalid and must be regenerated.</p></div><h2 id="setup-hash-your-passwords" tabindex="-1">Setup: hash your passwords <a class="header-anchor" href="#setup-hash-your-passwords" aria-label="Permalink to &quot;Setup: hash your passwords&quot;">​</a></h2><p>Add a password to your detection list:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> honey:hash-password</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;password123&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># NOT_TODAY_HONEY_PASSWORD_SHORT_SHA_LIST=7f4a2b1c</span></span></code></pre></div><p>Add multiple passwords and concatenate their hashes:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NOT_TODAY_HONEY_PASSWORD_SHORT_SHA_LIST=7f4a2b1c,3d9e1f2a,c8b05a44</span></span></code></pre></div><p>Once this variable is set, the built-in default list is automatically disabled (<code>include_defaults</code> becomes <code>false</code>).</p><h2 id="the-built-in-default-list" tabindex="-1">The built-in default list <a class="header-anchor" href="#the-built-in-default-list" aria-label="Permalink to &quot;The built-in default list&quot;">​</a></h2><p>When <code>NOT_TODAY_HONEY_PASSWORD_SHORT_SHA_LIST</code> is not set, a small built-in list of very common passwords is active. This gives you basic detection out of the box without any setup.</p><p>For production use, replace it with a custom list that matches the passwords attackers actually try against your stack. Public resources like <a href="https://github.com/danielmiessler/SecLists/tree/master/Passwords" target="_blank" rel="noreferrer">SecLists</a> provide curated credential lists.</p><h2 id="usernames" tabindex="-1">Usernames <a class="header-anchor" href="#usernames" aria-label="Permalink to &quot;Usernames&quot;">​</a></h2><p>Detection only escalates when both a recognised username <strong>and</strong> a recognised password are submitted together. Configure the username list:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NOT_TODAY_HONEY_USERNAMES=admin,administrator,webmaster,root,maintenance</span></span></code></pre></div><p>Extend this list to match the usernames common in your application&#39;s ecosystem (e.g. <code>wp-admin</code> for WordPress-specific attacks).</p><h2 id="what-happens-on-a-match" tabindex="-1">What happens on a match <a class="header-anchor" href="#what-happens-on-a-match" aria-label="Permalink to &quot;What happens on a match&quot;">​</a></h2><p>When a submitted credential pair matches:</p><ol><li>The alert level is set to <code>attacking</code></li><li><code>AttackerAttackingEvent</code> is dispatched</li><li>The IP is blocked for 30 days (default)</li></ol><p>See <a href="/configuration.html#credentials">Configuration → Credentials</a> for the full config reference.</p>`,32)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
